def get_email_cfg():
    try:
        return st.secrets["email"]["sender"], st.secrets["email"]["password"]
    except Exception:
        return os.getenv("EMAIL_SENDER",""), os.getenv("EMAIL_PASSWORD","")

# ─── DATABASE ────────────────────────────────────────────────────────────────
DB = "ojk_pengaduan.db"

def init_db():
    con = sqlite3.connect(DB)
    con.execute("""
        CREATE TABLE IF NOT EXISTS pengaduan (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            no_surat    TEXT,
            tipe        TEXT,
            nama        TEXT,
            nik         TEXT,
            alamat      TEXT,
            pt_dituju   TEXT,
            no_hp       TEXT,
            email       TEXT,
            kronologis  TEXT,
            kota        TEXT,
            tanggal     TEXT,
            created_at  TEXT
        )
    """)
    con.commit(); con.close()

def simpan_db(data: dict) -> int:
    con = sqlite3.connect(DB)
    cur = con.execute("""
        INSERT INTO pengaduan
        (no_surat,tipe,nama,nik,alamat,pt_dituju,no_hp,email,kronologis,kota,tanggal,created_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?)
    """, (
        data["no_surat"], data["tipe"], data["nama"], data["nik"],
        data["alamat"], data["pt_dituju"], data["no_hp"], data["email"],
        data["kronologis"], data["kota"], data["tanggal"],
        datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    ))
    con.commit(); row_id = cur.lastrowid; con.close()
    return row_id

def load_db():
    con = sqlite3.connect(DB)
    rows = con.execute("SELECT * FROM pengaduan ORDER BY id DESC").fetchall()
    cols = [d[0] for d in con.execute("SELECT * FROM pengaduan LIMIT 0").description or
            [("id",),("no_surat",),("tipe",),("nama",),("nik",),("alamat",),
             ("pt_dituju",),("no_hp",),("email",),("kronologis",),("kota",),("tanggal",),("created_at",)]]
    con.close()
    import pandas as pd
    if rows:
        cols2 = [d[0] for d in sqlite3.connect(DB).execute("SELECT * FROM pengaduan LIMIT 1").description]
        return pd.DataFrame(rows, columns=cols2)
    return pd.DataFrame()

def no_surat_baru(tipe):
    con = sqlite3.connect(DB)
    count = con.execute("SELECT COUNT(*) FROM pengaduan WHERE tipe=?", (tipe,)).fetchone()[0] + 1
    con.close()
    kode = "PENG" if tipe == "Surat Pengaduan" else "PERN"
    tahun = datetime.datetime.now().year
    return f"OJK-JBR/{kode}/{tahun}/{count:04d}"

# ─── EMAIL ───────────────────────────────────────────────────────────────────
def kirim_email(to_addr: str, nama: str, no_surat: str, pdf_bytes: bytes) -> tuple:
    sender, password = get_email_cfg()
    if not sender or not password:
        return False, "Konfigurasi email belum diisi di Streamlit Secrets."
    try:
        msg = MIMEMultipart()
        msg["From"]    = sender
        msg["To"]      = to_addr
        msg["Subject"] = f"Salinan Surat - {no_surat} | OJK Jember"
        body = f"""Yth. {nama},

Terlampir salinan surat Anda dengan nomor {no_surat} yang telah diproses oleh
Kantor OJK Jember.

Harap simpan email ini sebagai bukti pengiriman resmi.

Hormat kami,
Otoritas Jasa Keuangan - Kantor Jember
Layanan Perlindungan Konsumen
"""
        msg.attach(MIMEText(body, "plain"))
        part = MIMEBase("application", "octet-stream")
        part.set_payload(pdf_bytes)
        encoders.encode_base64(part)
        part.add_header("Content-Disposition",
                        f'attachment; filename="surat_{no_surat.replace("/","_")}.pdf"')
        msg.attach(part)
        with smtplib.SMTP(SMTP_HOST, SMTP_PORT) as s:
            s.starttls()
            s.login(sender, password)
            s.sendmail(sender, to_addr, msg.as_string())
        return True, "Email berhasil dikirim."
    except Exception as e:
        return False, str(e)

# ─── PDF / WORD ──────────────────────────────────────────────────────────────
TEKS_PERNYATAAN = (
    "menyatakan dengan sesungguhnya bahwa permasalahan yang saya ajukan melalui "
    "Aplikasi Portal Perlindungan Konsumen (APPK) tidak sedang dalam proses atau "
    "pernah diputus oleh lembaga arbitrase atau peradilan atau lembaga mediasi lainnya "
    "termasuk lembaga alternatif penyelesaian Sengketa dan belum pernah difasilitasi oleh OJK."
)
TEKS_PENUTUP = "Demikian surat pernyataan ini dibuat dengan sadar dan tanpa paksaan dari pihak manapun."

def bersihkan(t):
    if not t: return ""
    return t.encode("latin-1","replace").decode("latin-1")

def cetak_baris(pdf, label, nilai):
    pdf.cell(40,8,txt=label,ln=0); pdf.cell(5,8,txt=":",ln=0); pdf.cell(0,8,txt=nilai,ln=1)

def buat_pdf(d):
    pdf = FPDF(); pdf.add_page(); pdf.set_margins(20,20,20)
    if d["tipe"] == "Surat Pernyataan":
        pdf.set_font("Arial","B",14)
        pdf.cell(0,8,txt=bersihkan(d["no_surat"]),ln=True,align="R")
        pdf.ln(2)
        pdf.cell(0,10,txt="SURAT PERNYATAAN",ln=True,align="C")
        pdf.ln(6); pdf.set_font("Arial",size=12)
        pdf.cell(0,8,txt="Yang bertanda tangan di bawah ini:",ln=True)
        cetak_baris(pdf,"Nama",bersihkan(d["nama"]))
        cetak_baris(pdf,"NIK",bersihkan(d["nik"]))
        cetak_baris(pdf,"Alamat",bersihkan(d["alamat"]))
        pdf.ln(6); pdf.multi_cell(0,8,txt=bersihkan(TEKS_PERNYATAAN))
        pdf.ln(6); pdf.multi_cell(0,8,txt=bersihkan(TEKS_PENUTUP))
    else:
        pdf.set_font("Arial","B",14)
        pdf.cell(0,8,txt=bersihkan(d["no_surat"]),ln=True,align="R")
        pdf.ln(2)
        pdf.cell(0,10,txt="SURAT PENGADUAN",ln=True,align="C")
        pdf.ln(6); pdf.set_font("Arial",size=12)
        pdf.cell(0,8,txt=bersihkan(f"Kepada Yth. {d['pt_dituju']}"),ln=True)
        pdf.ln(4); pdf.cell(0,8,txt="Yang bertanda tangan di bawah ini:",ln=True)
        cetak_baris(pdf,"Nama",bersihkan(d["nama"]))
        cetak_baris(pdf,"NIK",bersihkan(d["nik"]))
        cetak_baris(pdf,"Alamat",bersihkan(d["alamat"]))
        cetak_baris(pdf,"No. HP",bersihkan(d["no_hp"]))
        cetak_baris(pdf,"Email",bersihkan(d["email"]))
        pdf.ln(5); pdf.cell(0,8,txt="Kronologis permasalahan:",ln=True)
        pdf.multi_cell(0,8,txt=bersihkan(d["kronologis"]))
    tgl_str = datetime.datetime.strptime(d["tanggal"],"%Y-%m-%d").strftime("%d %B %Y")
    pdf.ln(20); pdf.cell(110); pdf.cell(0,8,txt=bersihkan(f"{d['kota']}, {tgl_str}"),ln=True)
    pdf.ln(20); pdf.cell(110); pdf.cell(0,8,txt=bersihkan(f"({d['nama']})"),ln=True)
    return pdf.output(dest="S").encode("latin-1")

def buat_word(d):
    doc = Document()
    tgl_str = datetime.datetime.strptime(d["tanggal"],"%Y-%m-%d").strftime("%d %B %Y")
    if d["tipe"] == "Surat Pernyataan":
        p = doc.add_paragraph(d["no_surat"]); p.alignment = 2
        judul = doc.add_paragraph("SURAT PERNYATAAN"); judul.alignment = 1
        judul.runs[0].bold = True; judul.runs[0].font.size = Pt(14)
        doc.add_paragraph(""); doc.add_paragraph("Yang bertanda tangan di bawah ini:")
        doc.add_paragraph(f"Nama      : {d['nama']}")
        doc.add_paragraph(f"NIK       : {d['nik']}")
        doc.add_paragraph(f"Alamat    : {d['alamat']}")
        doc.add_paragraph(""); doc.add_paragraph(TEKS_PERNYATAAN)
        doc.add_paragraph(""); doc.add_paragraph(TEKS_PENUTUP)
    else:
        p = doc.add_paragraph(d["no_surat"]); p.alignment = 2
        judul = doc.add_paragraph("SURAT PENGADUAN"); judul.alignment = 1
        judul.runs[0].bold = True; judul.runs[0].font.size = Pt(14)
        doc.add_paragraph(""); doc.add_paragraph(f"Kepada Yth. {d['pt_dituju']}")
        doc.add_paragraph(""); doc.add_paragraph("Yang bertanda tangan di bawah ini:")
        doc.add_paragraph(f"Nama      : {d['nama']}")
        doc.add_paragraph(f"NIK       : {d['nik']}")
        doc.add_paragraph(f"Alamat    : {d['alamat']}")
        doc.add_paragraph(f"No. HP    : {d['no_hp']}")
        doc.add_paragraph(f"Email     : {d['email']}")
        doc.add_paragraph(""); doc.add_paragraph("Kronologis permasalahan:")
        doc.add_paragraph(d["kronologis"])
    doc.add_paragraph(""); doc.add_paragraph("")
    doc.add_paragraph(f"{'':>50}{d['kota']}, {tgl_str}")
    doc.add_paragraph(""); doc.add_paragraph("")
    doc.add_paragraph(f"{'':>50}({d['nama']})")
    buf = BytesIO(); doc.save(buf); buf.seek(0)
    return buf

